SELECT id, tx_id AS "txId", account_id AS "accountId", asset_code AS "assetCode",
       direction, amount, balance_after AS "balanceAfter", created_at AS "createdAt"
  FROM ledger_entry
 WHERE account_id = #{accountId}
 AND id < #{beforeId} 
 ORDER BY id DESC
 LIMIT #{limit}

SELECT id FROM ledger_tx
 WHERE reference_type = #{referenceType}
   AND reference_id   = #{referenceId}
   AND tx_type        = #{txType}
 LIMIT 1
